#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;

    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        int pu = find(u);
        int pv = find(v);
        if (pu == pv) return false;
        if (rank[pu] < rank[pv]) {
            parent[pu] = pv;
        } else if (rank[pu] > rank[pv]) {
            parent[pv] = pu;
        } else {
            parent[pv] = pu;
            rank[pu]++;
        }
        return true;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components > 1) {
        return -1;
    }

    auto can_form_spanning_tree = [&](long long min_s) {
        DSU temp_dsu(n);
        int temp_components = n;
        int upgrades_used = 0;

        for (const auto& e : must_edges) {
            if (e[2] >= min_s) {
                if (temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                }
            } else {
                return false;
            }
        }

        vector<vector<long long>> candidates;
        for (const auto& e : optional_edges) {
            if (e[2] >= min_s) {
                candidates.push_back({e[0], e[1]});
            } else if (e[2] * 2 >= min_s && upgrades_used < k) {
                candidates.push_back({e[0], e[1]});
                upgrades_used++;
            }
        }

        for (const auto& e : candidates) {
            if (temp_dsu.unite(e[0], e[1])) {
                temp_components--;
            }
        }

        return temp_components == 1 && upgrades_used <= k;
    };

    long long left = 1;
    long long right = 2e5;
    long long res = -1;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        if (can_form_spanning_tree(mid)) {
            res = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return res;
}

