	pu := d.Find(u)
	pv := d.Find(v)
	if pu == pv {
		return false
	}
	if d.rank[pu] < d.rank[pv] {
		d.parent[pu] = pv
	} else if d.rank[pu] > d.rank[pv] {
		d.parent[pv] = pu
	} else {
		d.parent[pv] = pu
		d.rank[pu]++
	}
	return true
}

